import React, { useState, useEffect } from 'react';
import axios from 'axios';

const AdminDashboard = () => {
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passInput, setPassInput] = useState("");

  // 1. Admin Security Check
  const handleAdminLogin = (e) => {
    e.preventDefault();
    if (passInput === "admin123") {
      setIsAuthenticated(true);
      fetchRequests();
    } else {
      alert("❌ Incorrect Admin Password!");
    }
  };

  const fetchRequests = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
      setLoading(false);
    } catch (err) { 
      console.error(err); 
      setLoading(false); 
    }
  };

  const handleUpdate = async (id, updatedData) => {
    try {
      await axios.put(`http://localhost:5000/api/update-status/${id}`, updatedData);
      fetchRequests(); 
    } catch (err) { 
      alert("Error updating!"); 
    }
  };

  // Login Screen
  if (!isAuthenticated) {
    return (
      <div className="admin-login-container d-flex align-items-center justify-content-center min-vh-100 bg-light">
        <div className="card shadow-lg p-4 border-0 rounded-4" style={{ width: '350px' }}>
          <h4 className="fw-bold text-center mb-4">Admin Portal</h4>
          <form onSubmit={handleAdminLogin}>
            <input 
              type="password" 
              className="form-control mb-3 text-center py-2" 
              placeholder="Enter Admin Password" 
              onChange={(e) => setPassInput(e.target.value)}
              required 
            />
            <button className="btn btn-primary w-100 fw-bold shadow py-2">Unlock Dashboard</button>
          </form>
        </div>
      </div>
    );
  }

  if (loading) return <div className="text-center py-5">Loading Admin Panel...</div>;

  return (
    <div className="admin-page bg-light min-vh-100 pb-5">
      
      {/* Header Section */}
      <div className="admin-header py-5 text-white shadow mb-5" style={{ background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)' }}>
        <div className="container d-flex justify-content-between align-items-center">
          <div>
            <h1 className="fw-bold mb-0">Admin <span className="text-warning">Control Panel</span></h1>
            <p className="opacity-75 mb-0">Track projects and manage client payments.</p>
          </div>
          <button className="btn btn-outline-light btn-sm fw-bold px-4 rounded-pill" onClick={() => setIsAuthenticated(false)}>Logout</button>
        </div>
      </div>

      <div className="container">
        <div className="row g-4">
          {requests.map((project) => {
            const remaining = project.totalBudget - project.advancePaid;
            return (
              <div key={project._id} className="col-12">
                <div className="card shadow-sm border-0 rounded-4 p-4 admin-card bg-white">
                  <div className="row align-items-center">
                    
                    {/* 1. Client Info */}
                    <div className="col-md-3 border-end">
                      <h5 className="fw-bold mb-0 text-dark text-capitalize">{project.fullName}</h5>
                      <span className="badge bg-primary-light text-primary mt-1 px-3 py-2 rounded-pill fw-bold text-uppercase" style={{fontSize: '10px'}}>
                        {project.serviceType}
                      </span>
                    </div>

                    {/* 2. Progress Slider */}
                    <div className="col-md-4 px-lg-4 text-center">
                      <div className="d-flex justify-content-between mb-2">
                        <small className="fw-bold text-muted text-uppercase">Progress</small>
                        <small className="fw-bold text-primary">{project.progress}%</small>
                      </div>
                      <div className="progress rounded-pill mb-3" style={{ height: '10px' }}>
                        <div className="progress-bar bg-primary progress-bar-striped progress-bar-animated" style={{ width: `${project.progress}%` }}></div>
                      </div>
                      <input 
                        type="range" className="form-range custom-slider" min="0" max="100" 
                        value={project.progress} 
                        onChange={(e) => handleUpdate(project._id, { progress: e.target.value })}
                      />
                    </div>

                    {/* 3. Payment Section */}
                    <div className="col-md-3 text-center border-start border-end">
                      <small className="text-muted d-block text-uppercase fw-bold letter-spacing">Remaining Balance</small>
                      <h3 className={`fw-bold mb-2 ${remaining > 0 ? 'text-danger' : 'text-success'}`}>
                        ₹{remaining}
                      </h3>
                      <div className="d-flex justify-content-center gap-2">
                        <button className="btn btn-xs btn-outline-dark fw-bold px-3 rounded-pill" style={{fontSize:'11px'}} onClick={() => {
                          const budget = prompt("Set Total Budget:", project.totalBudget);
                          if(budget) handleUpdate(project._id, { totalBudget: budget });
                        }}>Budget</button>
                        
                        <button className="btn btn-xs btn-outline-dark fw-bold px-3 rounded-pill" style={{fontSize:'11px'}} onClick={() => {
                          const paid = prompt("Enter Amount Paid:", project.advancePaid);
                          if(paid) {
                             const status = Number(paid) >= project.totalBudget ? 'Paid' : 'Unpaid';
                             handleUpdate(project._id, { advancePaid: paid, paymentStatus: status });
                          }
                        }}>Paid</button>
                      </div>
                    </div>

                    {/* 4. Delete Action */}
                    <div className="col-md-2 text-end">
                      <button className="btn btn-link text-danger p-0" title="Delete Project" onClick={() => {if(window.confirm("Delete record?")) axios.delete(`http://localhost:5000/api/delete-request/${project._id}`).then(fetchRequests)}}>
                        <i className="fas fa-trash-alt fa-lg"></i>
                      </button>
                    </div>

                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      <style>{`
        .admin-card { transition: all 0.3s ease; border: 1px solid rgba(0,0,0,0.05); }
        .admin-card:hover { transform: translateY(-5px); box-shadow: 0 15px 30px rgba(0,0,0,0.1) !important; }
        .bg-primary-light { background-color: #e7f0ff; }
        .letter-spacing { letter-spacing: 1px; font-size: 0.65rem; }
        .custom-slider { height: 6px; }
        @media (max-width: 768px) {
          .border-end, .border-start { border: none !important; margin-bottom: 15px; }
          .admin-card { text-align: center; }
        }
      `}</style>
    </div>
  );
};

export default AdminDashboard;
